import "./App.css";
import { Route, Routes } from "react-router-dom";
import Home from "./home.js";
import Header from "./header.js";

function App() {
  return (
    <div className="App">
      <Routes>
        <Route path="/" element={<Home></Home>}></Route>
        <Route path="/header" element={<Header></Header>}></Route>
      </Routes>
    </div>
  );
}

export default App;
